// Code (JavaScript) - ordenar por pubDate descendente (más reciente primero)
function parseDate(s){
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
}

return items.sort((a, b) => {
  const da = parseDate(a.json?.pubDate);
  const db = parseDate(b.json?.pubDate);
  const ta = da ? da.getTime() : 0;
  const tb = db ? db.getTime() : 0;
  return tb - ta; // descendente
});

