const items = $input.all();
let htmlFinal = "";

function getListItems(text) {
  const matches = text.match(/<li[\s\S]*?<\/li>/g);
  return matches ? matches.join(""):"";
}

htmlFinal += "<strong>International News</strong><br><br>";
htmlFinal += "<ol style='margin-left:20px;'>"
htmlFinal += getListItems(items[0].json.text);
htmlFinal += "</ol><br><br>";

htmlFinal += "<strong>Science News</strong><br><br>";
htmlFinal += "<ol style='margin-left:20px;'>"
htmlFinal += getListItems(items[1].json.text);
htmlFinal += "</ol><br><br>";

htmlFinal += "<strong>Technology News</strong><br><br>";
htmlFinal += "<ol style='margin-left:20px;'>"
htmlFinal += getListItems(items[2].json.text);
htmlFinal += "</ol><br><br>";

return { text: htmlFinal}

